pipeline {
    agent any
    tools { 
        //maven 'Maven_3.6.3'
        //jdk 'jdk_1.8.0_292'
        maven 'localMAVEN'
        jdk 'localJDK'
       }
	environment {
		//Use Pipeline Utility Steps plugin to read information from pom.xml into env variables
		IMAGE = readMavenPom().getArtifactId()
		VERSION = readMavenPom().getVersion()
		WORKSPACE = "${WORKSPACE}"
		JAVA_HOME_TARGET= "/etc/alternatives/java_sdk_1.8.0"
    }

    stages {
        stage('clean') {
            steps {
                sh 'mvn clean'
            }
        }

        stage('build') {
            steps {
                withMaven(
                    // Maven installation declared in the Jenkins "Global Tool Configuration"
                    maven: 'localMAVEN', // (1)
                    // Use `$WORKSPACE/.repository` for local repository folder to avoid shared repositories
                    // mavenLocalRepo: '.repository', // (2)
                    // Maven settings.xml file defined with the Jenkins Config File Provider Plugin
                    // We recommend to define Maven settings.xml globally at the folder level using
                    // navigating to the folder configuration in the section "Pipeline Maven Configuration / Override global Maven configuration"
                    // or globally to the entire master navigating to  "Manage Jenkins / Global Tools Configuration"
                    mavenSettingsConfig: 'b6139bf3-60c3-4d61-8d31-3f88e72fc548' // (3)
                ){
                    sh 'mvn compile'
                    sh 'mvn package'
                }
            }
        }

        stage('podman') {
            steps {

                sh '''#!/bin/bash -x
                   targetname=igfs3dsserver

                   #see if the pod already exist
                   ###############################
                   ###############################
                   ###############################
                   ###############################
                   counterPods=$(podman pod list | grep -c ${targetname})
                   if [[ $counterPods > 1 ]];then
                   	echo "Impossible to discriminate which pod to refresh. Use a more detailed name"
                   	exit 1
                   fi
                   if [[ $counterPods == 1 ]];then
                   	echo "Before to create the fresh Pod we will going to delete the old one"
                   	podman pod stop ${targetname}-pod
                   	podman pod rm ${targetname}-pod
                   fi

                   #see if the container already exist
                   ###############################
                   ###############################
                   ###############################
                   ###############################
                   counterContainers=$(podman container list -a | grep -c ${targetname})
                   if [[ $counterContainers > 1 ]];then
                   	echo "Impossible to discriminate which container to refresh. Use a more detailed name"
                   	exit 1
                   fi
                   if [[ $counterContainers == 1 ]];then
                   	echo "In this phase no container should be found. Investigate pls"
                   	exit 1
                   fi

                   #see if the image already exist
                   ###############################
                   ###############################
                   ###############################
                   ###############################
                   counterImages=$(podman image list --filter reference=*${targetname}*${VERSION}* --format "table {{.ID}}" --noheading | wc -l)
                   if [[ $counterImages -ge 1 ]];then
                    for idImage in $(podman image list --filter reference=*${targetname}*${VERSION}* --format "table {{.ID}}" --noheading); do
                        echo "Before to create the fresh Image we will going to delete the old one"
                        podman image rm $idImage
                    done
                   fi

                   ###############################
                   ###############################
                   ###############################
                   ###############################
                   sed -i "s/#VERSION/$VERSION/g" pod_${targetname}.yaml
                   sed -i "s/#IMAGE/$IMAGE/g" pod_${targetname}.yaml
                   podman build . --format docker --tag ${targetname}:${VERSION} --build-arg IMAGE=${IMAGE} --build-arg VERSION=${VERSION} --build-arg TARGETNAME=${targetname}
                   podman play kube pod_${targetname}.yaml
                   touch /var/lib/jenkins/basePodTmpl/fileSemaphores/semaphore_${targetname}_${VERSION}.sem

                '''
            }
        }
    }
}
